}

import React, { useState } from 'react';
import './styles.css';

interface ContactFormProps {
  apiUrl: string;
}

interface FormData {
  name: string;
  email: string;
  message: string;
}

interface FormErrors {
  name?: string;
  email?: string;
  message?: string;
}

// TODO: Implement form with validation and API submission
// 1. Validate fields on submit
// 2. POST to apiUrl
// 3. Handle loading/success/error states

export const ContactForm: React.FC<ContactFormProps> = ({ apiUrl }) => {
  const [form, setForm] = useState<FormData>({ name: '', email: '', message: '' });
  const [errors, setErrors] = useState<FormErrors>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);

  const handleChange = (field: keyof FormData, value: string) => {
    setForm(prev => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors(prev => ({ ...prev, [field]: undefined }));
    }
  };

  // TODO: Implement validate()
  // TODO: Implement handleSubmit()

  return (
    <form className="cform" onSubmit={e => { e.preventDefault(); /* TODO: call handleSubmit */ }}>
      {success && (
        <div data-testid="success-msg" className="cform__success">
          Message sent successfully!
        </div>
      )}

      {apiError && (
        <div data-testid="api-error" className="cform__api-error">
          {apiError}
        </div>
      )}

      <div className="cform__field">
        <label>Name</label>
        <input
          data-testid="name-input"
          className="cform__input"
          value={form.name}
          onChange={e => handleChange('name', e.target.value)}
          disabled={isSubmitting}
        />
        {errors.name && <span data-testid="name-error" className="cform__error">{errors.name}</span>}
      </div>

      <div className="cform__field">
        <label>Email</label>
        <input
          data-testid="email-input"
          className="cform__input"
          type="email"
          value={form.email}
          onChange={e => handleChange('email', e.target.value)}
          disabled={isSubmitting}
        />
        {errors.email && <span data-testid="email-error" className="cform__error">{errors.email}</span>}
      </div>

      <div className="cform__field">
        <label>Message</label>
        <textarea
          data-testid="message-input"
          className="cform__textarea"
          rows={4}
          value={form.message}
          onChange={e => handleChange('message', e.target.value)}
          disabled={isSubmitting}
        />
        {errors.message && <span data-testid="message-error" className="cform__error">{errors.message}</span>}
      </div>

      <button
        data-testid="submit-btn"
        className="cform__submit"
        type="submit"
        disabled={isSubmitting}
      >
        {isSubmitting ? 'Sending…' : 'Send Message'}
      </button>
    </form>
  );
};

.cform {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.cform__field {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.cform__field label {
  font-size: 0.8125rem;
  font-weight: 500;
  color: #374151;
}

.cform__input,
.cform__textarea {
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
}

.cform__input:focus,
.cform__textarea:focus {
  outline: 2px solid #3b82f6;
  outline-offset: 1px;
}

.cform__input:disabled,
.cform__textarea:disabled {
  background: #f3f4f6;
  cursor: not-allowed;
}

.cform__error {
  font-size: 0.75rem;
  color: #ef4444;
}

.cform__submit {
  padding: 0.5rem 1rem;
  border: none;
  border-radius: 0.375rem;
  background: #3b82f6;
  color: white;
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
}

.cform__submit:hover:not(:disabled) {
  background: #2563eb;
}

.cform__submit:disabled {
  background: #93c5fd;
  cursor: not-allowed;
}

.cform__success {
  padding: 0.75rem;
  background: #f0fdf4;
  color: #16a34a;
  border-radius: 0.375rem;
  font-size: 0.875rem;
}

.cform__api-error {
  padding: 0.75rem;
  background: #fef2f2;
  color: #ef4444;
  border-radius: 0.375rem;
  font-size: 0.875rem;
}

