import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';

let fetchMock: jest.Mock;

beforeEach(() => {
  fetchMock = jest.fn();
  global.fetch = fetchMock;
});

afterEach(() => {
  jest.restoreAllMocks();
});

import App from './App';

describe('Form Submission', () => {
  it('shows validation errors for empty fields', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('submit-btn'));
    expect(screen.getByTestId('name-error')).toBeInTheDocument();
    expect(screen.getByTestId('email-error')).toBeInTheDocument();
    expect(screen.getByTestId('message-error')).toBeInTheDocument();
  });

  it('shows error for invalid email', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('name-input'), { target: { value: 'John' } });
    fireEvent.change(screen.getByTestId('email-input'), { target: { value: 'notanemail' } });
    fireEvent.change(screen.getByTestId('message-input'), { target: { value: 'Hello' } });
    fireEvent.click(screen.getByTestId('submit-btn'));
    expect(screen.getByTestId('email-error')).toBeInTheDocument();
  });

  it('does not call fetch with invalid data', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('submit-btn'));
    expect(fetchMock).not.toHaveBeenCalled();
  });

  it('submits valid form and shows success', async () => {
    fetchMock.mockResolvedValue({ ok: true, json: () => Promise.resolve({}) });
    render(<App />);
    fireEvent.change(screen.getByTestId('name-input'), { target: { value: 'John' } });
    fireEvent.change(screen.getByTestId('email-input'), { target: { value: 'john@test.com' } });
    fireEvent.change(screen.getByTestId('message-input'), { target: { value: 'Hello' } });
    fireEvent.click(screen.getByTestId('submit-btn'));
    await waitFor(() => {
      expect(screen.getByTestId('success-msg')).toBeInTheDocument();
    });
  });

  it('shows api error on failure', async () => {
    fetchMock.mockRejectedValue(new Error('Server error'));
    render(<App />);
    fireEvent.change(screen.getByTestId('name-input'), { target: { value: 'John' } });
    fireEvent.change(screen.getByTestId('email-input'), { target: { value: 'john@test.com' } });
    fireEvent.change(screen.getByTestId('message-input'), { target: { value: 'Hello' } });
    fireEvent.click(screen.getByTestId('submit-btn'));
    await waitFor(() => {
      expect(screen.getByTestId('api-error')).toBeInTheDocument();
    });
  });

  it('disables button during submission', async () => {
    fetchMock.mockReturnValue(new Promise(() => {}));
    render(<App />);
    fireEvent.change(screen.getByTestId('name-input'), { target: { value: 'John' } });
    fireEvent.change(screen.getByTestId('email-input'), { target: { value: 'john@test.com' } });
    fireEvent.change(screen.getByTestId('message-input'), { target: { value: 'Hello' } });
    fireEvent.click(screen.getByTestId('submit-btn'));
    expect(screen.getByTestId('submit-btn')).toBeDisabled();
  });
});

