import React, { useState } from 'react';
import './styles.css';

interface ContactFormProps {
  apiUrl: string;
}

interface FormData {
  name: string;
  email: string;
  message: string;
}

interface FormErrors {
  name?: string;
  email?: string;
  message?: string;
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export const ContactForm: React.FC<ContactFormProps> = ({ apiUrl }) => {
  const [form, setForm] = useState<FormData>({ name: '', email: '', message: '' });
  const [errors, setErrors] = useState<FormErrors>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);

  const handleChange = (field: keyof FormData, value: string) => {
    setForm(prev => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors(prev => ({ ...prev, [field]: undefined }));
    }
    setSuccess(false);
    setApiError(null);
  };

  const validate = (): FormErrors => {
    const errs: FormErrors = {};
    if (!form.name.trim()) errs.name = 'Name is required';
    if (!form.email.trim()) errs.email = 'Email is required';
    else if (!EMAIL_REGEX.test(form.email)) errs.email = 'Invalid email format';
    if (!form.message.trim()) errs.message = 'Message is required';
    return errs;
  };

  const handleSubmit = async () => {
    const errs = validate();
    setErrors(errs);
    if (Object.keys(errs).length > 0) return;

    setIsSubmitting(true);
    setApiError(null);
    setSuccess(false);

    try {
      const res = await fetch(apiUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(form),
      });
      if (!res.ok) throw new Error(`HTTP error ${res.status}`);
      setSuccess(true);
      setForm({ name: '', email: '', message: '' });
    } catch (err: any) {
      setApiError(err.message || 'Something went wrong');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form className="cform" onSubmit={e => { e.preventDefault(); handleSubmit(); }}>
      {success && (
        <div data-testid="success-msg" className="cform__success">Message sent successfully!</div>
      )}

      {apiError && (
        <div data-testid="api-error" className="cform__api-error">{apiError}</div>
      )}

      <div className="cform__field">
        <label>Name</label>
        <input data-testid="name-input" className="cform__input" value={form.name} onChange={e => handleChange('name', e.target.value)} disabled={isSubmitting} />
        {errors.name && <span data-testid="name-error" className="cform__error">{errors.name}</span>}
      </div>

      <div className="cform__field">
        <label>Email</label>
        <input data-testid="email-input" className="cform__input" type="email" value={form.email} onChange={e => handleChange('email', e.target.value)} disabled={isSubmitting} />
        {errors.email && <span data-testid="email-error" className="cform__error">{errors.email}</span>}
      </div>

      <div className="cform__field">
        <label>Message</label>
        <textarea data-testid="message-input" className="cform__textarea" rows={4} value={form.message} onChange={e => handleChange('message', e.target.value)} disabled={isSubmitting} />
        {errors.message && <span data-testid="message-error" className="cform__error">{errors.message}</span>}
      </div>

      <button data-testid="submit-btn" className="cform__submit" type="submit" disabled={isSubmitting}>
        {isSubmitting ? 'Sending…' : 'Send Message'}
      </button>
    </form>
  );
};
